fields.collector:
$path = 'HKLM:\SYSTEM\CurrentControlSet\Control\CloudDomainJoin\JoinInfo'
$joinKey = Get-ChildItem -Path $path -ErrorAction SilentlyContinue | Select-Object -First 1 -ExpandProperty PSChildName
if ($joinKey) {
    if ([guid]::TryParse($joinKey, [ref][guid]::Empty)) {
        $cert = Get-ChildItem -Path 'Cert:\LocalMachine\My' -Recurse | Where-Object { $_.Subject -like "CN=$joinKey" } | Select-Object -First 1
    } else {
        $cert = Get-ChildItem -Path 'Cert:\LocalMachine\My' -Recurse | Where-Object { $_.Thumbprint -eq $joinKey } | Select-Object -First 1
    }
    if ($cert) { ($cert.Subject -replace 'CN=', '') }
}
